162: 	m.initNamespaceSelector.Do(func() {
163: 		m.namespaceSelector, m.namespaceSelectorErr = metav1.LabelSelectorAsSelector(m.NamespaceSelector)
164: 	})
165: 	return m.namespaceSelector, m.namespaceSelectorErr
166: }
